@@ -1134,9 +1134,75 @@ static Value *foldUnsignedUnderflowCheck(ICmpInst *ZeroICmp,

   return nullptr;
 }
+/// Fold (icmp ne X, C) & (icmp ule (add X, -C), Y) -> icmp ult (add X, -C-1), Y.
+/// Fold (icmp eq X, C) | (icmp ugt (add X, -C), Y) -> icmp uge (add X, -C-1), Y.
+/// Generalizes to any constant C, where the add constant is -C.
+static Value *foldAddNoWrapCheck(ICmpInst *Cmp0, ICmpInst *Cmp1, bool IsAnd,
+                                 const SimplifyQuery &Q,
+                                 InstCombiner::BuilderTy &Builder) {
+  ICmpInst::Predicate Pred0 = Cmp0->getPredicate();
+  ICmpInst::Predicate Pred1 = Cmp1->getPredicate();
+  Value *X, *Y;
+  const APInt *CmpC, *AddC;
+  // Match equality with any constant.
+  bool IsEqCmp0 = ICmpInst::isEquality(Pred0) &&
+                  match(Cmp0->getOperand(1), m_APInt(CmpC));
+  bool IsEqCmp1 = ICmpInst::isEquality(Pred1) &&
+                  match(Cmp1->getOperand(1), m_APInt(CmpC));
+  if (!IsEqCmp0 && !IsEqCmp1)
+    return nullptr;
+
+  // Determine which is the equality compare and which is the add compare.
+  ICmpInst *EqCmp = IsEqCmp0 ? Cmp0 : Cmp1;
+  ICmpInst *AddCmp = IsEqCmp0 ? Cmp1 : Cmp0;
+  ICmpInst::Predicate EqPred = EqCmp->getPredicate();
+  ICmpInst::Predicate AddPred = AddCmp->getPredicate();
+
+  // The equality compare must be NE for AND, EQ for OR.
+  if (IsAnd && EqPred != ICmpInst::ICMP_NE)
+    return nullptr;
+  if (!IsAnd && EqPred != ICmpInst::ICMP_EQ)
+    return nullptr;
+
+  // Match add compare: icmp ule (add X, CAdd), Y or swapped.
+  Value *AddOp0 = AddCmp->getOperand(0);
+  Value *AddOp1 = AddCmp->getOperand(1);
+  // Check if one operand is add with constant.
+  Value *AddLHS;
+  const APInt *One;
+  bool AddIsOp0 = match(AddOp0, m_Add(m_Value(AddLHS), m_APInt(One)));
+  bool AddIsOp1 = !AddIsOp0 && match(AddOp1, m_Add(m_Value(AddLHS), m_APInt(One)));
+  if (!AddIsOp0 && !AddIsOp1)
+    return nullptr;
+
+  X = AddLHS;
+  // Ensure the X matches the operand of the equality compare.
+  if (EqCmp->getOperand(0) != X)
+    return nullptr;
+
+  // Determine the other operand (Y).
+  Y = AddIsOp0 ? AddOp1 : AddOp0;
+  // Normalize predicate to the form (X + CAdd) <= Y (for AND) or (X + CAdd) > Y (for OR).
+  ICmpInst::Predicate NormPred = AddIsOp0 ? AddPred : ICmpInst::getSwappedPredicate(AddPred);

-struct IntPart {
-  Value *From;
+  // Predicate must be unsigned less-or-equal (ULE) for AND, unsigned greater (UGT) for OR.
+  if (IsAnd && NormPred != ICmpInst::ICMP_ULE)
+    return nullptr;
+  if (!IsAnd && NormPred != ICmpInst::ICMP_UGT)
+    return nullptr;
+
+  // Check that the constants satisfy CmpC = -One.
+  if (*CmpC != -(*One))
+    return nullptr;
+
+  // Fold to (X + (CAdd - 1)) < Y for AND, (X + (CAdd - 1)) >= Y for OR.
+  APInt NewAddC = *One - 1;
+  Value *NewAdd = NewAddC.isZero() ? X : Builder.CreateAdd(X, ConstantInt::get(X->getType(), NewAddC));
+  if (IsAnd)
+    return Builder.CreateICmpULT(NewAdd, Y);
+  else
+    return Builder.CreateICmpUGE(NewAdd, Y);
+}
   unsigned StartBit;
   unsigned NumBits;
 };
